import { HydrateClient } from "@repo/app-trpc/server";
import {
  SidebarInset,
  SidebarProvider,
  SidebarTrigger,
} from "@repo/ui/components/ui/sidebar";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { Loader2 } from "lucide-react";
import { notFound } from "next/navigation";
import { Suspense } from "react";
import { AppHeader } from "~/components/app-header";
import { AppSidebar } from "~/components/app-sidebar";
import { CommandPalette } from "~/components/command-palette";
import { OrgPageErrorBoundary } from "~/components/errors/org-page-error-boundary";
import { GitHubBindStep } from "~/components/github-bind-step";
import { getGitHubBinding } from "~/lib/github-binding";
import { requireOrgAccess } from "~/lib/org-access-clerk";

interface OrgLayoutProps {
  children: React.ReactNode;
  params: Promise<{ slug: string }>;
}

/**
 * Organization layout - prefetches org data using user-scoped endpoint
 *
 * Flow:
 * 1. Layout verifies org access via requireOrgAccess (fetches org directly from Clerk by slug)
 * 2. Validates org access and sets up org context
 * 3. Procedure manually verifies user has access to the org
 * 4. Middleware's organizationSyncOptions syncs org from URL (happens in parallel)
 * 5. Data is hydrated to client → fast render
 * 6. Failure → error boundary catches → proper error UI
 *
 * Why we use requireOrgAccess instead of auth().orgSlug:
 * - After org name changes, setActive() updates cookies but there's propagation delay
 * - auth().orgSlug might return old slug or null during RSC request
 * - requireOrgAccess fetches org directly from Clerk by slug and verifies membership
 * - This avoids race conditions with Clerk cookie propagation
 */
export default async function OrgLayout({ children, params }: OrgLayoutProps) {
  const { slug } = await params;

  let org: { id: string; name: string } | null = null;
  try {
    const access = await requireOrgAccess(slug);
    org = { id: access.org.id, name: access.org.name };
  } catch (error) {
    log.debug("[org-layout] access denied", { slug, error: parseError(error) });
    notFound();
  }

  // Check GitHub binding — render setup UI if missing
  // NOTE: This conditional JSX return is a new pattern in this codebase. All other
  // layouts use early exits (notFound/redirect). We use conditional rendering here
  // because redirecting to a sub-route of [slug]/ would create a redirect loop.
  const binding = await getGitHubBinding(org.id);
  if (!binding || binding.status !== "active") {
    // No HydrateClient needed — no server prefetches for the bind step.
    // useTRPC() in GitHubBindStep is provided by TRPCReactProvider higher in the tree.
    return <GitHubBindStep orgName={org.name} />;
  }

  return (
    <HydrateClient>
      <OrgPageErrorBoundary orgSlug={slug}>
        <SidebarProvider className="!h-full !min-h-0 overflow-hidden bg-sidebar">
          <AppSidebar />
          <CommandPalette />
          {/* Right column: header (outside inset) + inset content below */}
          {/* pr-2 pb-2 creates the gap for the inset card — margin on SidebarInset doesn't work because w-full overflows */}
          <div className="flex min-h-0 flex-1 flex-col overflow-hidden lg:pr-2 lg:pb-2">
            {/* h-14 header — same visual level as sidebar's team-switcher row */}
            <div className="flex h-14 shrink-0 items-center px-4">
              <SidebarTrigger className="lg:hidden" />
              <Suspense fallback={<div className="h-8 w-8" />}>
                <AppHeader />
              </Suspense>
            </div>
            {/* Inset panel: 100% - h-14, rounded card floating in bg-sidebar */}
            <SidebarInset className="overflow-hidden lg:rounded-xl lg:shadow-sm">
              <Suspense fallback={<PageLoadingSkeleton />}>{children}</Suspense>
            </SidebarInset>
          </div>
        </SidebarProvider>
      </OrgPageErrorBoundary>
    </HydrateClient>
  );
}

function PageLoadingSkeleton() {
  return (
    <div className="flex h-full min-h-0 w-full items-center justify-center">
      <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
    </div>
  );
}

"use client";

import { Check, ChevronsUpDown, Circle, Plus } from "lucide-react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { useState } from "react";
import { cn } from "../../lib/utils";
import { Avatar, AvatarFallback } from "../ui/avatar";
import { Button } from "../ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu";

type TeamSwitcherMode = "organization" | "account";

interface Organization {
  id: string;
  name: string;
  slug: string | null;
  githubBound?: boolean;
}

interface TeamSwitcherProps {
  /** Href for "Create Team" link (e.g., "/account/teams/new") */
  createTeamHref: string;
  /**
   * Mode determines what is displayed:
   * - "organization": Shows current organization name
   * - "account": Shows "My Account" but allows switching to organizations
   */
  mode?: TeamSwitcherMode;
  /** Called when user selects an org — app should handle auth SDK (e.g., clerk.setActive) */
  onOrgSelect: (orgId: string, orgSlug: string) => Promise<void>;
  /** List of organizations the user belongs to */
  organizations: Organization[];
}

export type { Organization, TeamSwitcherMode, TeamSwitcherProps };

export function TeamSwitcher({
  organizations,
  mode = "organization",
  onOrgSelect,
  createTeamHref,
}: TeamSwitcherProps) {
  const [open, setOpen] = useState(false);
  const pathname = usePathname();
  const router = useRouter();

  // Extract org slug from pathname (e.g., /someteam/... -> someteam)
  const currentOrgSlug = (() => {
    if (mode === "account") {
      return null;
    }
    const pathParts = pathname.split("/").filter(Boolean);
    const reservedRoutes = ["new", "account", "api", "sign-in", "sign-up"];
    if (pathParts[0] && !reservedRoutes.includes(pathParts[0])) {
      return pathParts[0];
    }
    return null;
  })();

  const currentOrg = currentOrgSlug
    ? organizations.find((org) => org.slug === currentOrgSlug)
    : null;

  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2);
  };

  const displayText =
    mode === "account" ? "My Account" : (currentOrg?.name ?? "Select team");
  const displayInitials =
    mode === "account" ? "MA" : currentOrg ? getInitials(currentOrg.name) : "?";

  return (
    <DropdownMenu onOpenChange={setOpen} open={open}>
      <div className="flex items-center gap-1">
        {mode === "organization" && currentOrg ? (
          <Link
            className="flex min-w-0 items-center gap-2"
            href={`/${currentOrg.slug}`}
            onClick={async (e) => {
              if (e.ctrlKey || e.metaKey || e.shiftKey || e.altKey) {
                return;
              }
              e.preventDefault();
              await onOrgSelect(currentOrg.id, currentOrg.slug ?? "");
              router.push(`/${currentOrg.slug}`);
            }}
            prefetch={true}
          >
            <Avatar className="size-6">
              <AvatarFallback className="bg-foreground text-[10px] text-background">
                {displayInitials}
              </AvatarFallback>
            </Avatar>
            <span className="truncate font-medium text-base">
              {displayText}
            </span>
          </Link>
        ) : (
          <div className="flex min-w-0 items-center gap-2">
            <Avatar className="size-6">
              <AvatarFallback className="bg-foreground text-[10px] text-background">
                {displayInitials}
              </AvatarFallback>
            </Avatar>
            <span className="truncate font-medium text-base">
              {displayText}
            </span>
          </div>
        )}

        <DropdownMenuTrigger asChild>
          <Button className="h-6 w-6 rounded-full" size="sm" variant="ghost">
            <ChevronsUpDown className="size-3.5 opacity-50" />
          </Button>
        </DropdownMenuTrigger>
      </div>
      <DropdownMenuContent align="center" className="w-[220px] space-y-1">
        {organizations.map((org) => {
          const isSelected =
            mode === "organization" && currentOrg?.id === org.id;

          return (
            <DropdownMenuItem
              asChild
              className={cn(
                "cursor-pointer rounded-xl px-2",
                isSelected && "bg-muted/50"
              )}
              key={org.id}
            >
              <Link
                href={`/${org.slug}`}
                onClick={async (e) => {
                  if (e.ctrlKey || e.metaKey || e.shiftKey || e.altKey) {
                    return;
                  }
                  e.preventDefault();
                  setOpen(false);
                  await onOrgSelect(org.id, org.slug ?? "");
                  router.push(`/${org.slug}`);
                }}
                prefetch={true}
              >
                <Avatar className="h-5 w-5 shrink-0">
                  <AvatarFallback className="bg-foreground text-[10px] text-background">
                    {getInitials(org.name)}
                  </AvatarFallback>
                </Avatar>
                <span className="flex-1 truncate">{org.name}</span>
                {org.githubBound === false && (
                  <Circle className="h-2 w-2 shrink-0 fill-current text-amber-500" />
                )}
                {isSelected && (
                  <Check className="h-4 w-4 shrink-0 text-foreground" />
                )}
              </Link>
            </DropdownMenuItem>
          );
        })}

        <DropdownMenuItem
          asChild
          className="cursor-pointer rounded-xl px-2 text-muted-foreground"
        >
          <Link href={{ pathname: createTeamHref }} prefetch={true}>
            <div className="flex h-5 w-5 items-center justify-center rounded-full border border-border/50 border-dashed">
              <Plus className="h-3 w-3" />
            </div>
            <span>Create Team</span>
          </Link>
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { UserMenu } from "@repo/ui/components/app-header/user-menu";
import { useSuspenseQuery } from "@tanstack/react-query";
import { useClerk } from "@vendor/clerk/client";
import Link from "next/link";
/**
 * Application header - full width with org switcher on left and user actions on right
 */
export function AppHeader() {
  const trpc = useTRPC();
  const { signOut } = useClerk();

  const { data: profile } = useSuspenseQuery({
    ...trpc.account.get.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });

  const email = profile.primaryEmailAddress ?? profile.username ?? "";

  const initials = (() => {
    const { firstName, lastName, fullName, username } = profile;
    if (fullName) {
      return fullName
        .split(" ")
        .map((n) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2);
    }
    if (firstName && lastName) {
      return `${firstName[0]}${lastName[0]}`.toUpperCase();
    }
    if (firstName) {
      return firstName.substring(0, 2).toUpperCase();
    }
    if (lastName) {
      return lastName.substring(0, 2).toUpperCase();
    }
    if (username) {
      return username.substring(0, 2).toUpperCase();
    }
    return "LF";
  })();

  return (
    <div className="flex w-full items-center pl-2">
      <div />
      {/* Right side - Notifications and User dropdown */}
      <div className="ml-auto flex items-center gap-3">
        <Link
          className="text-muted-foreground text-sm hover:text-foreground"
          href="https://lightfast.ai/docs/get-started/overview"
          rel="noopener noreferrer"
          target="_blank"
        >
          Docs
        </Link>
        <Link
          className="text-muted-foreground text-sm hover:text-foreground"
          href="https://lightfast.ai/docs/api-reference"
          rel="noopener noreferrer"
          target="_blank"
        >
          API Reference
        </Link>
        <UserMenu
          email={email}
          initials={initials}
          onSignOut={() => void signOut({ redirectUrl: "/sign-in" })}
          settingsHref="/account/settings/general"
        />
      </div>
    </div>
  );
}

"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { TeamSwitcher } from "@repo/ui/components/app-header/team-switcher";
import { Button } from "@repo/ui/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@repo/ui/components/ui/popover";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@repo/ui/components/ui/sidebar";
import { platformModifierKey } from "@repo/ui/lib/platform";
import { cn } from "@repo/ui/lib/utils";
import { useSuspenseQuery } from "@tanstack/react-query";
import { useOrganizationList } from "@vendor/clerk/client";
import {
  Activity,
  BookOpen,
  Boxes,
  Briefcase,
  HelpCircle,
  Mail,
  MessageSquare,
  Plug,
  Search,
  Settings,
} from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";

/**
 * Navigation item types
 */
interface NavItem {
  href: string;
  icon: React.ComponentType<{ className?: string }>;
  title: string;
}

/**
 * Build primary navigation items for org-level pages
 */
function getOrgPrimaryItems(orgSlug: string): NavItem[] {
  return [
    {
      title: "Explore",
      href: `/${orgSlug}`,
      icon: MessageSquare,
    },
    {
      title: "Entities",
      href: `/${orgSlug}/entities`,
      icon: Boxes,
    },
  ];
}

/**
 * Build management navigation items for org-level pages
 */
function getOrgManageItems(orgSlug: string): NavItem[] {
  return [
    {
      title: "Events",
      href: `/${orgSlug}/events`,
      icon: Activity,
    },
    {
      title: "Sources",
      href: `/${orgSlug}/sources`,
      icon: Plug,
    },
    {
      title: "Jobs",
      href: `/${orgSlug}/jobs`,
      icon: Briefcase,
    },
    {
      title: "Settings",
      href: `/${orgSlug}/settings`,
      icon: Settings,
    },
  ];
}

/**
 * Render a set of navigation items as a proper component for correct reconciliation
 */
function NavItems({ items, pathname }: { items: NavItem[]; pathname: string }) {
  return items.map((item) => {
    // For Settings, match any settings subpage (org or workspace level)
    const isActive =
      item.title === "Settings"
        ? pathname.startsWith(item.href)
        : pathname === item.href;

    return (
      <SidebarMenuItem key={item.title}>
        <SidebarMenuButton
          asChild
          className={cn(
            "rounded-xl [&>svg]:size-3.5",
            isActive
              ? "text-foreground data-[active=true]:text-foreground"
              : "text-muted-foreground"
          )}
          isActive={isActive}
          size="sm"
        >
          <Link href={{ pathname: item.href }} prefetch={true}>
            <item.icon className="size-3.5" />
            <span>{item.title}</span>
          </Link>
        </SidebarMenuButton>
      </SidebarMenuItem>
    );
  });
}

/**
 * PlanetScale-style sidebar component for the Console app
 */
export function AppSidebar() {
  const pathname = usePathname();
  const trpc = useTRPC();
  const { setActive } = useOrganizationList();

  const { data: organizations = [] } = useSuspenseQuery({
    ...trpc.organization.listUserOrganizations.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });

  const handleOrgSelect = async (orgId: string) => {
    if (setActive) {
      await setActive({ organization: orgId });
    }
  };

  // Extract orgSlug from pathname
  // Pathname format: /[slug]/...
  const pathParts = pathname.split("/").filter(Boolean);
  const orgSlug = pathParts[0] ?? ""; // [slug]

  // Determine mode based on pathname
  const mode =
    pathname.startsWith("/account") || pathname.startsWith("/new")
      ? "account"
      : "organization";

  return (
    <Sidebar className="group/sidebar" collapsible="offcanvas" variant="inset">
      {/* Org component header - only show if in org context */}
      {orgSlug && (
        <div className="flex h-14 items-center justify-between px-4">
          <TeamSwitcher
            createTeamHref="/account/teams/new"
            mode={mode}
            onOrgSelect={handleOrgSelect}
            organizations={organizations}
          />
          <Button
            className="h-6 w-6 rounded-full text-muted-foreground"
            onClick={() => {
              document.dispatchEvent(
                new KeyboardEvent("keydown", {
                  key: "k",
                  ...platformModifierKey(),
                  bubbles: true,
                  cancelable: true,
                  composed: true,
                })
              );
            }}
            size="icon"
            title="Search (⌘K)"
            variant="ghost"
          >
            <Search className="size-3.5" />
          </Button>
        </div>
      )}
      <SidebarContent>
        {orgSlug && (
          <>
            {/* Primary Navigation - no label */}
            <SidebarGroup className="pt-0">
              <SidebarGroupContent>
                <SidebarMenu>
                  <NavItems
                    items={getOrgPrimaryItems(orgSlug)}
                    pathname={pathname}
                  />
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>

            {/* Manage Section */}
            <SidebarGroup collapsible defaultOpen label="Manage">
              <SidebarGroupContent>
                <SidebarMenu>
                  <NavItems
                    items={getOrgManageItems(orgSlug)}
                    pathname={pathname}
                  />
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>
          </>
        )}
      </SidebarContent>
      <SidebarFooter>
        <Popover>
          <PopoverTrigger asChild>
            <Button
              className="h-8 w-8 rounded-full bg-muted p-1"
              size="icon"
              title="Help"
              variant="outline"
            >
              <HelpCircle className="size-3.5" />
            </Button>
          </PopoverTrigger>
          <PopoverContent align="center" className="w-48 p-0.5">
            <div className="flex flex-col gap-1">
              <Button
                asChild
                className="justify-start gap-2 rounded-xl text-sm"
                size="sm"
                variant="ghost"
              >
                <a href="mailto:support@lightfast.ai">
                  <Mail className="size-3.5" />
                  Contact Support
                </a>
              </Button>
              <Button
                asChild
                className="justify-start gap-2 rounded-xl text-sm"
                size="sm"
                variant="ghost"
              >
                <Link
                  href="https://lightfast.ai/docs/get-started/overview"
                  rel="noopener noreferrer"
                  target="_blank"
                >
                  <BookOpen className="size-3.5" />
                  Help Docs
                </Link>
              </Button>
            </div>
          </PopoverContent>
        </Popover>
      </SidebarFooter>
    </Sidebar>
  );
}

