1	
2	import { Check, ChevronsUpDown, Circle, Plus } from "lucide-react";
3	import Link from "next/link";
4	import { usePathname, useRouter } from "next/navigation";
5	import { useState } from "react";
6	import { cn } from "../../lib/utils";
7	import { Avatar, AvatarFallback } from "../ui/avatar";
8	import { Button } from "../ui/button";
9	import {
10	  DropdownMenu,
11	  DropdownMenuContent,
12	  DropdownMenuItem,
13	  DropdownMenuTrigger,
14	} from "../ui/dropdown-menu";
15	
16	type TeamSwitcherMode = "organization" | "account";
17	
18	interface Organization {
19	  id: string;
20	  name: string;
21	  slug: string | null;
22	  githubBound?: boolean;
23	}
24	
25	interface TeamSwitcherProps {
26	  /** Href for "Create Team" link (e.g., "/account/teams/new") */
27	  createTeamHref: string;
28	  /**
29	   * Mode determines what is displayed:
30	   * - "organization": Shows current organization name
31	   * - "account": Shows "My Account" but allows switching to organizations
32	   */
33	  mode?: TeamSwitcherMode;
34	  /** Called when user selects an org — app should handle auth SDK (e.g., clerk.setActive) */
35	  onOrgSelect: (orgId: string, orgSlug: string) => Promise<void>;
36	  /** List of organizations the user belongs to */
37	  organizations: Organization[];
38	}
39	
40	export type { Organization, TeamSwitcherMode, TeamSwitcherProps };
41	
42	export function TeamSwitcher({
43	  organizations,
44	  mode = "organization",
45	  onOrgSelect,
46	  createTeamHref,
47	}: TeamSwitcherProps) {
48	  const [open, setOpen] = useState(false);
49	  const pathname = usePathname();
50	  const router = useRouter();
51	
52	  // Extract org slug from pathname (e.g., /someteam/... -> someteam)
53	  const currentOrgSlug = (() => {
54	    if (mode === "account") {
55	      return null;
56	    }
57	    const pathParts = pathname.split("/").filter(Boolean);
58	    const reservedRoutes = ["new", "account", "api", "sign-in", "sign-up"];
59	    if (pathParts[0] && !reservedRoutes.includes(pathParts[0])) {
60	      return pathParts[0];
61	    }
62	    return null;
63	  })();
64	
65	  const currentOrg = currentOrgSlug
66	    ? organizations.find((org) => org.slug === currentOrgSlug)
67	    : null;
68	
69	  const getInitials = (name: string) => {
70	    return name
71	      .split(" ")
72	      .map((n) => n[0])
73	      .join("")
74	      .toUpperCase()
75	      .slice(0, 2);
76	  };
77	
78	  const displayText =
79	    mode === "account" ? "My Account" : (currentOrg?.name ?? "Select team");
80	  const displayInitials =
81	    mode === "account" ? "MA" : currentOrg ? getInitials(currentOrg.name) : "?";
82	
83	  return (
84	    <DropdownMenu onOpenChange={setOpen} open={open}>
85	      <div className="flex items-center gap-1">
86	        {mode === "organization" && currentOrg ? (
87	          <Link
88	            className="flex min-w-0 items-center gap-2"
89	            href={`/${currentOrg.slug}`}
90	            onClick={async (e) => {
91	              if (e.ctrlKey || e.metaKey || e.shiftKey || e.altKey) {
92	                return;
93	              }
94	              e.preventDefault();
95	              await onOrgSelect(currentOrg.id, currentOrg.slug ?? "");
96	              router.push(`/${currentOrg.slug}`);
97	            }}
98	            prefetch={true}
99	          >
100	            <Avatar className="size-6">
101	              <AvatarFallback className="bg-foreground text-[10px] text-background">
102	                {displayInitials}
103	              </AvatarFallback>
104	            </Avatar>
105	            <span className="truncate font-medium text-base">
106	              {displayText}
107	            </span>
108	          </Link>
109	        ) : (
110	          <div className="flex min-w-0 items-center gap-2">
111	            <Avatar className="size-6">
112	              <AvatarFallback className="bg-foreground text-[10px] text-background">
113	                {displayInitials}
114	              </AvatarFallback>
115	            </Avatar>
116	            <span className="truncate font-medium text-base">
117	              {displayText}
118	            </span>
119	          </div>
120	        )}
121	
122	        <DropdownMenuTrigger asChild>
123	          <Button className="h-6 w-6 rounded-full" size="sm" variant="ghost">
124	            <ChevronsUpDown className="size-3.5 opacity-50" />
125	          </Button>
126	        </DropdownMenuTrigger>
