  const trpc = useTRPC();
  const { setActive } = useOrganizationList();

  const { data: organizations = [] } = useSuspenseQuery({
    ...trpc.organization.listUserOrganizations.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });

  const handleOrgSelect = async (orgId: string) => {
    if (setActive) {
      await setActive({ organization: orgId });
    }
  };

  return (
    <>
      <TeamSwitcher
        createTeamHref="/account/teams/new"
        mode="organization"
        onOrgSelect={handleOrgSelect}
        organizations={organizations}
      />
      <Button
        className="h-6 w-6 rounded-full text-muted-foreground"
        onClick={() => {
          document.dispatchEvent(
            new KeyboardEvent("keydown", {
              key: "k",
              ...platformModifierKey(),
              bubbles: true,
              cancelable: true,
              composed: true,
            })
          );
        }}
        size="icon"
        title="Search (⌘K)"
        variant="ghost"
      >
        <Search className="size-3.5" />
      </Button>
    </>
  );
}
```

**Why a separate component rather than inlining?**
- It requires `"use client"` (hooks: `useSuspenseQuery`, `useOrganizationList`).
- The workspace layout is a server component. Client logic must be in a separate file.
- `UserPageHeader` (existing) follows this exact same pattern -- a client component that fetches orgs + profile and renders `TeamSwitcher` + `UserMenu`.

**Data flow**: Both `WorkspaceHeader` and `AppSidebar` call `trpc.organization.listUserOrganizations.queryOptions()`. React Query deduplicates -- the data is prefetched in `(app)/layout.tsx` (line 8), so both components read from cache with zero network requests.

No shared hook is needed. The `useActiveOrg` hook in `packages/app-trpc` already does something similar (reads from the same query cache). But `WorkspaceHeader` needs the full `organizations` array, not just the active org. Keep the separate `useSuspenseQuery` calls in both components -- they are trivial and React Query handles deduplication.

---

### Part 5: `AppSidebar` Changes

**File**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/components/app-sidebar.tsx`

**Changes**:
1. Add `className` prop to `<Sidebar>` for the desktop top offset: `className="group/sidebar !top-14 !h-[calc(100svh-3.5rem)]"`
2. Wrap the h-14 TeamSwitcher header section with `lg:hidden` so it only appears in the mobile Sheet.
3. Keep all nav items and footer unchanged.

Modified structure:
```tsx
export function AppSidebar() {
  // ... existing hooks ...

  return (
    <Sidebar 
      className="group/sidebar !top-14 !h-[calc(100svh-3.5rem)]" 
      collapsible="offcanvas" 
      variant="inset"
    >
      {/* TeamSwitcher header - mobile Sheet only */}
      {orgSlug && (
        <div className="flex h-14 items-center justify-between px-4 lg:hidden">
          <TeamSwitcher ... />
          <SearchButton ... />
        </div>
      )}
      <SidebarContent>
        {/* ... nav items unchanged ... */}
      </SidebarContent>
      <SidebarFooter>
        {/* ... unchanged ... */}
      </SidebarFooter>
    </Sidebar>
  );
}
```

**Mobile behavior**: On mobile, the `Sidebar` component renders a `Sheet` (slide-in drawer). The `className` prop is NOT applied to the Sheet (confirmed from sidebar source line 172-194 -- the className is spread via `{...props}` on the `Sheet` component, but the inner `SheetContent` doesn't receive it). So `!top-14` has no effect on mobile -- exactly what we want. The `lg:hidden` wrapper around TeamSwitcher means on mobile (`< 1024px`), the TeamSwitcher IS visible in the Sheet. On desktop (`>= 1024px`), it is hidden because it lives in the workspace header instead.

**Wait -- re-checking**: The `Sidebar` component spreads `{...props}` on the `Sheet` when `isMobile` is true (line 174), but `className` is destructured separately and NOT passed to Sheet. So `!top-14 !h-[calc(...)]` is correctly desktop-only.

Actually, re-reading lines 143-153 of sidebar.tsx:
```tsx
function Sidebar({
  side = "left",
  variant = "sidebar",
  collapsible = "offcanvas",
  className,    // <-- destructured out
  children,
  ...props      // <-- remaining props
}) {
```
And line 174: `<Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>` -- `className` is NOT in `...props`. Correct.

---

### Part 6: Onboard Route

#### `[slug]/onboard/layout.tsx` (NEW)

Server component. Renders a header-only shell for the onboard flow.

```tsx
import { Suspense } from "react";
import { AppHeader } from "~/components/app-header";
import { OnboardHeader } from "~/components/onboard-header";
import { requireOrgAccess } from "~/lib/org-access-clerk";

interface OnboardLayoutProps {
  children: React.ReactNode;
  params: Promise<{ slug: string }>;
}

export default async function OnboardLayout({ children, params }: OnboardLayoutProps) {
  const { slug } = await params;
  // React.cache'd -- no extra Clerk call
  const { org } = await requireOrgAccess(slug);

  return (
    <div className="flex h-full flex-col">
      <div className="flex h-14 shrink-0 items-center justify-between px-4">
        <Suspense fallback={<div className="h-6 w-24" />}>
          <OnboardHeader />
        </Suspense>
        <Suspense fallback={<div className="h-8 w-8" />}>
          <AppHeader />
        </Suspense>
      </div>
      <div className="flex-1 overflow-auto">
        {children}
      </div>
    </div>
  );
}
```

#### `OnboardHeader` Component (NEW)

**File**: `apps/app/src/components/onboard-header.tsx`

Simpler variant -- just `TeamSwitcher`, no search button. All viewports.

```tsx
"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { TeamSwitcher } from "@repo/ui/components/app-header/team-switcher";
import { useSuspenseQuery } from "@tanstack/react-query";
import { useOrganizationList } from "@vendor/clerk/client";

export function OnboardHeader() {
  const trpc = useTRPC();
  const { setActive } = useOrganizationList();

  const { data: organizations = [] } = useSuspenseQuery({
    ...trpc.organization.listUserOrganizations.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });

  const handleOrgSelect = async (orgId: string) => {
    if (setActive) {
      await setActive({ organization: orgId });
    }
  };

  return (
    <TeamSwitcher
      createTeamHref="/account/teams/new"
      mode="organization"
      onOrgSelect={handleOrgSelect}
      organizations={organizations}
    />
  );
}
```

**Alternative (answering Question 1)**: Instead of two separate components (`WorkspaceHeader` and `OnboardHeader`), we could create a single `OrgHeader` component with a `variant` prop. However, the two are different enough -- `WorkspaceHeader` includes the search button and is rendered inside a `SidebarProvider` context, while `OnboardHeader` is standalone. Keeping them separate avoids conditional logic and makes each file easy to reason about. The data-fetching logic is identical but trivial (3 lines). Not worth abstracting.

#### `[slug]/onboard/page.tsx` (NEW)

Redirects to the current onboard step.

```tsx
import { redirect } from "next/navigation";

interface OnboardPageProps {
  params: Promise<{ slug: string }>;
}

export default async function OnboardPage({ params }: OnboardPageProps) {
  const { slug } = await params;
  // For now, GitHub is always the first (and only) step.
  // Future: check which steps are complete and redirect to the next incomplete one.
  redirect(`/${slug}/onboard/github`);
}
```

#### `[slug]/onboard/github/page.tsx` (NEW)

Evolves from the existing `GitHubBindStep` component. The key difference: on success, instead of `router.refresh()`, it navigates to `/${slug}` (the workspace home).

```tsx
import { getGitHubBinding } from "~/lib/github-binding";
import { requireOrgAccess } from "~/lib/org-access-clerk";
import { redirect } from "next/navigation";
import { GitHubConnectStep } from "~/components/github-connect-step";

interface GitHubOnboardPageProps {
  params: Promise<{ slug: string }>;
}

export default async function GitHubOnboardPage({ params }: GitHubOnboardPageProps) {
  const { slug } = await params;
  const { org } = await requireOrgAccess(slug);

  // If already bound, skip to workspace
  const binding = await getGitHubBinding(org.id);
  if (binding && binding.status === "active") {
    redirect(`/${slug}`);
  }

  return <GitHubConnectStep orgName={org.name} orgSlug={slug} />;
}
```

#### Evolve `GitHubBindStep` --> `GitHubConnectStep`

**File**: Rename `apps/app/src/components/github-bind-step.tsx` to `apps/app/src/components/github-connect-step.tsx`

Changes:
1. Add `orgSlug` prop.
2. On success, `router.push(`/${orgSlug}`)` instead of `router.refresh()`. This navigates to the workspace, which now exists as a separate route group with its own binding check.
3. Keep all existing UI (stepper, error handling, OAuth popup logic).

```tsx
interface GitHubConnectStepProps {
  orgName: string;
  orgSlug: string;
}

export function GitHubConnectStep({ orgName, orgSlug }: GitHubConnectStepProps) {
  const router = useRouter();
  // ...

  const { handleConnect, isConnecting } = useOAuthPopup({
    provider: "github",
    queryKeysToInvalidate: [
      trpc.githubBinding.get.queryKey(),
      trpc.connections.generic.listInstallations.queryKey(),
      trpc.organization.listUserOrganizations.queryKey(),
    ],
    onSuccess: () => {
      router.push(`/${orgSlug}`);
    },
  });
  // ... rest unchanged ...
}
```

---

### Part 7: Handling the `SidebarProvider` CSS Override

The proposed `SidebarProvider` className: `"!h-full !min-h-0 flex-col overflow-hidden bg-sidebar"`.

The `SidebarProvider` internally applies: `"group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full"`.

The final computed classes: `group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full !h-full !min-h-0 flex-col overflow-hidden bg-sidebar`.

- `flex` + `flex-col` = vertical stacking (correct).
- `min-h-svh` is overridden by `!min-h-0` (correct -- we want the provider to fill the parent, not exceed it).
- `!h-full` forces `height: 100%` to match the parent `<div class="flex flex-1 overflow-hidden">` from `(app)/layout.tsx`.

This combination is correct and matches the intent.

---

### Part 8: Edge Cases and Verification Checklist

1. **Redirect loop prevention**: The `(workspace)/layout.tsx` checks binding and redirects to `/[slug]/onboard`. The `onboard/github/page.tsx` checks binding and redirects back to `/[slug]` if already bound. No loop possible because the conditions are mutually exclusive.

2. **Org access denied on onboard**: The `[slug]/layout.tsx` calls `requireOrgAccess` and `notFound()`s on failure. This protects both onboard and workspace routes.

3. **Mobile TeamSwitcher on onboard**: The onboard layout renders `TeamSwitcher` directly in the header at all viewports. No sidebar exists, so the `SidebarTrigger` hamburger is absent. The `TeamSwitcher` is always visible.

4. **Mobile TeamSwitcher on workspace**: On mobile, the header's left column (`hidden lg:flex`) is hidden. The `SidebarTrigger` appears in the right column. When the user opens the sidebar Sheet, `TeamSwitcher` is visible in the Sheet (via the `lg:hidden` wrapper in `AppSidebar`).

5. **CommandPalette context**: `CommandPalette` uses `useActiveOrg` which reads from URL params. It is placed inside `(workspace)/layout.tsx` after the sidebar, maintaining the current pattern. On onboard routes, no `CommandPalette` exists -- this is intentional (no workspace search during onboard).

6. **`SidebarInset` peer styles**: As analyzed, the peer-based styles on `SidebarInset` are not effective in the current nesting structure. The visual gap is achieved by the wrapper div's `lg:pr-2 lg:pb-2` and explicit className on `SidebarInset`. No regression.

7. **Future onboard steps**: The `/[slug]/onboard/page.tsx` redirect-based router makes it easy to add steps. Just add new directories (`/[slug]/onboard/sources/`, etc.) and update the redirect logic to check which steps are complete.

---

### Part 9: Implementation Sequence

**Phase 1: Foundation (no visual changes)**
1. Wrap `requireOrgAccess` with `React.cache()` in `~/lib/org-access-clerk.ts`.
2. Create the `(workspace)` route group directory.
3. Move `page.tsx`, `_components/`, and `(manage)/` into `(workspace)/` via `git mv`.
4. Create `(workspace)/layout.tsx` by extracting the sidebar shell from `[slug]/layout.tsx` (minus the binding check initially -- just pass children through).
5. Slim down `[slug]/layout.tsx` to org access + error boundary only.
6. Verify: all existing routes work identically.

**Phase 2: Onboard route**
7. Create `onboard/layout.tsx`, `onboard/page.tsx`, `onboard/github/page.tsx`.
8. Create `GitHubConnectStep` component (rename + modify `GitHubBindStep`).
9. Create `OnboardHeader` component.
10. Add the binding check + redirect to `(workspace)/layout.tsx`.
11. Remove `GitHubBindStep` import and conditional from `[slug]/layout.tsx`.
12. Verify: new orgs without binding see onboard flow, existing orgs see workspace.

**Phase 3: Header restructuring**
13. Create `WorkspaceHeader` component.
14. Update `(workspace)/layout.tsx` to the full header-above-content layout (with `flex-col`, header row, sidebar+content row).
15. Update `AppSidebar`: add `className` for top offset, wrap TeamSwitcher header with `lg:hidden`.
16. Verify: desktop shows TeamSwitcher above sidebar, mobile shows TeamSwitcher in Sheet.

**Phase 4: Cleanup**
17. Delete the old `GitHubBindStep` component (or rename in Phase 2).
18. Remove unused imports from `[slug]/layout.tsx`.
19. Verify all responsive breakpoints.

---

### Answers to Specific Questions

**Q1: Shared `OrgHeader` vs inline JSX?**
Separate components: `WorkspaceHeader` (TeamSwitcher + search, used in workspace layout) and `OnboardHeader` (TeamSwitcher only, used in onboard layout). Both are client components with minimal, non-overlapping logic. A shared component would add conditional branching for marginal DRY gains. Keep them separate.

**Q2: Data flow for `organizations` + `onOrgSelect`?**
Both `WorkspaceHeader` and `AppSidebar` independently call `useSuspenseQuery(trpc.organization.listUserOrganizations.queryOptions())`. React Query deduplicates. The data is prefetched in `(app)/layout.tsx`. No shared hook needed. The pattern is already established by `UserPageHeader` and `AppSidebar` both doing independent fetches.

**Q3: `SidebarProvider` `flex-col` override?**
Yes, adding `flex-col` to the className works. The combined classes `flex min-h-svh w-full !h-full !min-h-0 flex-col overflow-hidden bg-sidebar` produce the correct vertical stacking. The `!min-h-0` overrides `min-h-svh`, and `!h-full` constrains height to the parent.

**Q4: Onboard org context?**
The onboard layout calls `requireOrgAccess(slug)` which is `React.cache()`'d, so it reuses the result from the parent `[slug]/layout.tsx` call within the same server request. Zero extra cost. The `orgName` needed for "Setting up {orgName}" is passed as a prop to the `GitHubConnectStep` component from the server page component.

---

### Critical Files for Implementation
- `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/app/(app)/(org)/[slug]/layout.tsx` -- slim down to org access only
- `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/components/app-sidebar.tsx` -- add top offset className, wrap TeamSwitcher with `lg:hidden`
- `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/lib/org-access-clerk.ts` -- wrap with `React.cache()`
- `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/components/github-bind-step.tsx` -- evolve into `GitHubConnectStep` with `orgSlug` prop and `router.push` on success
- `/Users/jeevanpillay/Code/@lightfastai/lightfast/packages/ui/src/components/ui/sidebar.tsx` -- reference only (no changes needed, but critical to understand the `fixed` positioning, `peer` mechanics, and mobile Sheet behavior)

