```tsx
import { redirect } from "next/navigation";
import { GitHubConnectStep } from "~/components/github-connect-step";
import { getGitHubBinding } from "~/lib/github-binding";
import { requireOrgAccess } from "~/lib/org-access-clerk";

export default async function GitHubOnboardPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const { org } = await requireOrgAccess(slug);

  // Already bound? Skip to workspace
  const binding = await getGitHubBinding(org.id);
  if (binding && binding.status === "active") {
    redirect(`/${slug}`);
  }

  return <GitHubConnectStep orgName={org.name} orgSlug={slug} />;
}
```

**Redirect loop prevention**: Workspace layout redirects to `/[slug]/onboard` when no binding. Onboard github page redirects to `/[slug]` when binding exists. Conditions are mutually exclusive — no loop.

