git mv apps/app/src/app/\(app\)/\(org\)/\[slug\]/_components \
       apps/app/src/app/\(app\)/\(org\)/\[slug\]/\(workspace\)/_components
git mv apps/app/src/app/\(app\)/\(org\)/\[slug\]/\(manage\) \
