### 2.2 Create `OnboardHeader` component

**File**: NEW at `apps/app/src/components/onboard-header.tsx`

Follows the same pattern as `UserPageHeader` (`components/user-page-header.tsx`). Renders TeamSwitcher + AppHeader (Docs, API, UserMenu). Visible at all viewports since there's no sidebar.

```tsx
"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { TeamSwitcher } from "@repo/ui/components/app-header/team-switcher";
import { UserMenu } from "@repo/ui/components/app-header/user-menu";
import { useSuspenseQuery } from "@tanstack/react-query";
import { useClerk, useOrganizationList } from "@vendor/clerk/client";
import Link from "next/link";

export function OnboardHeader() {
  const trpc = useTRPC();
  const { signOut } = useClerk();
  const { setActive } = useOrganizationList();

  const { data: profile } = useSuspenseQuery({
    ...trpc.account.get.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });
  const { data: organizations = [] } = useSuspenseQuery({
    ...trpc.organization.listUserOrganizations.queryOptions(),
    staleTime: 5 * 60 * 1000,
  });

  const handleOrgSelect = async (orgId: string) => {
    if (setActive) await setActive({ organization: orgId });
  };

  const email = profile.primaryEmailAddress ?? profile.username ?? "";
  const initials = /* same initials logic as AppHeader */;

  return (
    <div className="flex h-14 shrink-0 items-center px-4">
      <TeamSwitcher
        createTeamHref="/account/teams/new"
        mode="organization"
        onOrgSelect={handleOrgSelect}
        organizations={organizations}
      />
      <div className="ml-auto flex items-center gap-3">
        <Link className="text-muted-foreground text-sm hover:text-foreground" href="..." target="_blank">Docs</Link>
