import { redirect } from "next/navigation";
import { GitHubConnectStep } from "~/components/github-connect-step";
import { getGitHubBinding } from "~/lib/github-binding";
import { requireOrgAccess } from "~/lib/org-access-clerk";

interface GitHubOnboardPageProps {
  params: Promise<{ slug: string }>;
}

/**
 * GitHub onboard step — connect a GitHub organization to the Lightfast team.
 * If already bound, redirects to the workspace.
 */
export default async function GitHubOnboardPage({
  params,
}: GitHubOnboardPageProps) {
  const { slug } = await params;
  const { org } = await requireOrgAccess(slug); // cache()'d — deduped with parent layout

  // Already bound? Skip to workspace
  const binding = await getGitHubBinding(org.id);
  if (binding && binding.status === "active") {
    redirect(`/${slug}`);
  }

  return <GitHubConnectStep orgName={org.name} orgSlug={slug} />;
}

